import { Card } from '@tale-ui/react/card';
import { Text } from '@tale-ui/react/text';
import { Button } from '@tale-ui/react/button';

export function CardWithContent() {
  return (
    <Card.Root>
      <Card.Header>
        <Text variant="title" size="m">Welcome</Text>
      </Card.Header>
      <Card.Body>
        <Text variant="text" size="m">
          This is your personal dashboard. Here you can manage your account settings, view recent activity, and explore new features.
        </Text>
      </Card.Body>
      <Card.Footer>
        <Button variant="primary">Get Started</Button>
      </Card.Footer>
    </Card.Root>
  );
}
